--
-- Table structure for table `user_devices`
--

DROP TABLE IF EXISTS `user_devices`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `user_devices` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '기본키',
  `user_id` bigint NOT NULL COMMENT 'users.id 참조',
  `device_fingerprint` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '기기 고유 해시 (UA 기반)',
  `device_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'mobile | desktop | tablet',
  `os` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '운영체제 정보',
  `browser` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '브라우저 정보',
  `ip_address` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '마지막 접속 IP (IPv6 포함)',
  `is_trusted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '신뢰 기기 여부 (2차 인증 통과 후 등록)',
  `last_used_at` datetime DEFAULT NULL COMMENT '마지막 사용 일시',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '최초 등록 일시',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_ud_user_fp` (`user_id`,`device_fingerprint`),
  KEY `idx_ud_user_id` (`user_id`),
  CONSTRAINT `fk_ud_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='사용자 기기 정보 및 신뢰 기기 관리';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `user_devices`
--

LOCK TABLES `user_devices` WRITE;
/*!40000 ALTER TABLE `user_devices` DISABLE KEYS */;
/*!40000 ALTER TABLE `user_devices` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `users`
--

DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `users` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '자동 증가 기본키',
  `email` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '이메일 (로그인 식별자)',
  `password_hash` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'bcrypt 해시된 비밀번호',
  `name` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '표시용 이름 (닉네임 또는 실명)',
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '휴대폰 번호',
  `role` enum('user','admin') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'user' COMMENT '권한 구분 (회원가입 시 항상 user로 고정)',
  `is_email_verified` tinyint(1) NOT NULL DEFAULT '0' COMMENT '이메일 인증 여부 (0: 미인증, 1: 인증완료)',
  `is_locked` tinyint(1) NOT NULL DEFAULT '0' COMMENT '계정 잠금 여부 (로그인 실패 누적 시 1)',
  `status` enum('active','dormant','withdrawn') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active' COMMENT '계정 상태',
  `provider` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '소셜 로그인 제공자 (kakao, google 등)',
